#include <concepts>
#include <iostream>

template <typename T>
concept Addable = requires(T a, T b) { { a + b } -> std::convertible_to<T>; };

template <Addable T>
T add(const T& a, const T& b) { return a + b; }

int main() {
    long long a{}, b{}, c{};
    if (!(std::cin >> a >> b >> c)) return 1;
    std::cout << add(add(a, b), c) << '\n';
}
